            ContentJson = """{"title":"Admin Field Reference","groups":[{"heading":"User Form Fields","items":[{"label":"First Name (required)","value":"Text input, max 100 chars. Validated as required."},{"label":"Last Name (required)","value":"Text input, max 100 chars. Validated as required."},{"label":"Email (required, create only)","value":"Email input, max 256 chars. Validated as required + email format. Hidden when editing (email cannot change)."},{"label":"Initials (optional)","value":"Text input, max 3 chars. Auto-generated from name if blank. Shown on avatar."},{"label":"Role (required)","value":"Dropdown select. Options: Engineer, ProductionWorker, PM, Manager, OfficeManager, Admin. Determines feature access."},{"label":"Work Location (optional)","value":"Dropdown select. Only shown when multiple company locations exist. Drives state withholding form requirements."},{"label":"Avatar Color","value":"12-color button grid. Click a color swatch to set the avatar background color."},{"label":"Is Active (edit only)","value":"Toggle switch. Deactivating prevents login but preserves all historical data."},{"label":"Scan Identifiers (edit only)","value":"List of RFID/NFC/Barcode/Biometric IDs. Add via type dropdown + value input + Add button. Remove individually."}]},{"heading":"User Actions","items":[{"label":"Add User button","value":"Opens user creation dialog. Admin never sets passwords — system generates a setup token."},{"label":"Get Setup Code","value":"Generates a secure token URL for the user to complete their account setup. Shown for users without passwords."},{"label":"Copy Setup Code","value":"Copies the setup token URL to clipboard for sharing via email or message."},{"label":"Edit User (pencil icon)","value":"Opens edit dialog pre-filled with current values. Tooltip: 'Edit'."},{"label":"Toggle Active (person icon)","value":"Deactivates or reactivates the user. Tooltip: 'Deactivate' or 'Activate'."},{"label":"RFID Reader status","value":"Shows connected/disconnected indicator. Download RFID setup script button available."}]},{"heading":"Track Type Dialog Fields","items":[{"label":"Name (required)","value":"Text input. The display name for this track type (e.g., 'Production', 'R&D/Tooling')."},{"label":"Code (required)","value":"Text input. Pattern: uppercase letters, numbers, underscores only (^[A-Z0-9_]+$). Immutable identifier."},{"label":"Description (optional)","value":"Text input. Brief explanation of when this track type is used."},{"label":"Stage Name","value":"Text input per stage. The display name for each stage (e.g., 'In Production', 'QC/Review')."},{"label":"Stage Code","value":"Text input per stage. Immutable identifier per stage."},{"label":"Stage Color","value":"Color picker input per stage. Sets the column header color on the kanban board."},{"label":"WIP Limit","value":"Number input per stage. When exceeded, column header turns red. 0 or blank = no limit."},{"label":"Irreversible checkbox","value":"Per stage. When checked, jobs cannot move backward past this stage (used for Invoice, Payment stages with accounting documents)."},{"label":"Move Up/Down buttons","value":"Reorder stages. Disabled if already first/last."},{"label":"Add Stage button","value":"Adds a new blank stage row to the list."},{"label":"Delete Stage button","value":"Removes a stage. At least one stage required."}]},{"heading":"Company Profile Fields","items":[{"label":"Company Name","value":"Text input. Appears on invoices, packing slips, and customer-facing documents."},{"label":"Phone","value":"Text input with phone mask: (XXX) XXX-XXXX format."},{"label":"Email","value":"Email input. Company-wide contact email."},{"label":"EIN","value":"Text input. Placeholder: XX-XXXXXXX. Employer Identification Number."},{"label":"Website","value":"Text input. Placeholder: https://. Company website URL."}]},{"heading":"Company Location Fields","items":[{"label":"Name (required)","value":"Text input, max 100 chars. Location display name (e.g., 'Main Office', 'Warehouse B')."},{"label":"Phone","value":"Text input with phone mask."},{"label":"Address","value":"AddressFormComponent (street, city, state dropdown, zip). Full address fields."},{"label":"Is Active (edit only)","value":"Toggle switch. Inactive locations hidden from new user assignment."},{"label":"Set as Default button","value":"Marks this location as the company default. Only one default allowed."}]},{"heading":"Events Dialog Fields","items":[{"label":"Title (required)","value":"Text input, max 200 chars. data-testid: event-title"},{"label":"Event Type (required)","value":"Select: Meeting, Training, Safety, Other. data-testid: event-type"},{"label":"Location","value":"Text input, optional. data-testid: event-location"},{"label":"Start Date (required)","value":"Datepicker. data-testid: event-start-date"},{"label":"Start Time (required)","value":"Text input, placeholder: HH:MM. data-testid: event-start-time"},{"label":"End Date (required)","value":"Datepicker. data-testid: event-end-date"},{"label":"End Time (required)","value":"Text input, placeholder: HH:MM. data-testid: event-end-time"},{"label":"Description","value":"Textarea, optional. data-testid: event-description"},{"label":"Attendees","value":"Multi-select user dropdown."},{"label":"Required","value":"Toggle. When ON, attendees get mandatory notifications. data-testid: event-required"},{"label":"Save button","value":"data-testid: event-save-btn. Disabled when form invalid or saving."}]},{"heading":"AI Assistant Dialog Fields","items":[{"label":"Name (required)","value":"Text, max 100. Display name shown in sidebar card."},{"label":"Description","value":"Text, max 500. Shown below name in card and welcome screen."},{"label":"Category (required)","value":"Select: General, HR, Procurement, Sales, Custom."},{"label":"Icon (required)","value":"Text, max 50. Material icon name (e.g., smart_toy). Default: smart_toy."},{"label":"Color (required)","value":"Color picker. Default: #0d9488. Used for icon background."},{"label":"System Prompt (required)","value":"Textarea, max 50000. The AI's behavior instructions."},{"label":"Allowed Entity Types","value":"Multi-select. 20 entity types the assistant can search across."},{"label":"Starter Questions","value":"Dynamic list with add/remove. Pre-populated conversation starters."},{"label":"Temperature (advanced)","value":"Number, 0-1, default 0.7. Controls AI response creativity."},{"label":"Max Context Chunks (advanced)","value":"Number, 1-20, default 5. How many RAG chunks to include."}]},{"heading":"EDI Trading Partner Fields","items":[{"label":"Name (required)","value":"Text, max 200. Trading partner display name."},{"label":"Qualifier ID (required)","value":"Text, max 10. Default: ZZ. EDI qualifier code."},{"label":"Qualifier Value (required)","value":"Text, max 100. Trading partner identifier value."},{"label":"Default Format","value":"Select: X12, EDIFACT."},{"label":"Transport Method","value":"Select: AS2, SFTP, VAN, Email, API, Manual."},{"label":"Auto Process","value":"Toggle, default ON. Automatically process incoming transactions."},{"label":"Require Acknowledgment","value":"Toggle, default ON. Require functional acknowledgments."},{"label":"Notes","value":"Textarea, optional."}]},{"heading":"Audit Log Filters","items":[{"label":"Entity Type","value":"Select: All Types, Job, Part, Customer, Vendor, Invoice, Payment, etc."},{"label":"Action","value":"Text input. Filter by action name (Create, Update, Delete)."},{"label":"From Date","value":"Datepicker. Start of date range filter."},{"label":"To Date","value":"Datepicker. End of date range filter."},{"label":"Pagination","value":"Page size options: 25, 50, 100. Default: 25."}]},{"heading":"Sales Tax Rate Fields","items":[{"label":"Name (required)","value":"Text, max 100. Display name for the tax rate."},{"label":"Code (required)","value":"Text, max 20. Unique identifier code."},{"label":"State Code","value":"Select dropdown. US state for this rate."},{"label":"Rate Percent (required)","value":"Number, 0-100. The tax percentage."},{"label":"Effective From","value":"Datepicker. When this rate takes effect."},{"label":"Description","value":"Textarea, optional."},{"label":"Is Default","value":"Toggle. Sets this as the default tax rate."}]}]}"""
