            ContentJson = """{"passingScore":75,"questionsPerQuiz":10,"shuffleOptions":true,"showExplanationsAfterSubmit":true,"questions":[{"id":"ad1","text":"A new employee needs to be set up in QB Engineer. What is the correct process?","options":[{"id":"a","text":"Go to Admin → Users, click Add User, set their password, and give them their login credentials"},{"id":"b","text":"Go to Admin → Users, click Add User, fill in their details — the system generates a setup token the employee uses to set their own password","isCorrect":true},{"id":"c","text":"Ask the employee to self-register on the login page and then approve their account"},{"id":"d","text":"Create their profile in Account → Profile and assign a temporary password"}],"explanation":"Admins never set passwords. The system generates a secure setup token URL. Share this with the employee — they follow the link to set their own password and complete their account."},{"id":"ad2","text":"You want to add a new kanban board for tracking maintenance work orders. Where do you do this?","options":[{"id":"a","text":"Kanban Board → Settings → Add Board"},{"id":"b","text":"Admin → Track Types → New Track Type — define the name, code, and stages","isCorrect":true},{"id":"c","text":"Admin → Settings → Board Configuration"},{"id":"d","text":"You cannot add new board types — only the default ones are available"}],"explanation":"Track types define kanban boards. Go to Admin → Track Types and click New Track Type. Define the stages with names, codes, colors, WIP limits, and irreversibility flags."},{"id":"ad3","text":"An employee is leaving the company. What should you do with their account?","options":[{"id":"a","text":"Delete their account from Admin → Users"},{"id":"b","text":"Toggle their Is Active switch to OFF — this prevents login but preserves all historical data","isCorrect":true},{"id":"c","text":"Remove their role so they can't access anything"},{"id":"d","text":"Change their password to something random"}],"explanation":"Never delete user accounts. Toggle Is Active to OFF to deactivate. The user can no longer log in, but all their historical data (jobs, time entries, expenses, activity logs) remains intact for reporting and compliance."},{"id":"ad4","text":"Your company just opened a second warehouse. How do you register it in the system?","options":[{"id":"a","text":"Admin → Settings → Company Locations → New Location — enter name, address, and state","isCorrect":true},{"id":"b","text":"Inventory → Locations → Create Warehouse"},{"id":"c","text":"Admin → Integrations → Add Location"},{"id":"d","text":"You can only have one location in QB Engineer"}],"explanation":"Company locations are managed in Admin → Settings → Locations. Add the new location with its name and address. Employees assigned to this location will get the correct state withholding forms."},{"id":"ad5","text":"You want to rename 'Jobs' to 'Work Orders' throughout the entire application. Where do you make this change?","options":[{"id":"a","text":"Admin → Settings → Application Name"},{"id":"b","text":"Admin → Terminology — find the entity_job key and enter 'Work Orders' as the custom label","isCorrect":true},{"id":"c","text":"This requires a code change — custom labels aren't supported"},{"id":"d","text":"Admin → Reference Data → Jobs group → rename the label"}],"explanation":"The Terminology tab lets you customize any application label. Find entity_job, enter 'Work Orders', and click Save. The change applies immediately across the entire app for all users."},{"id":"ad6","text":"A track type stage is marked as 'Irreversible'. What does this mean?","options":[{"id":"a","text":"The stage name cannot be renamed or edited"},{"id":"b","text":"Jobs in this stage cannot move backward to a previous stage — typically because accounting documents (invoices, payments) are attached","isCorrect":true},{"id":"c","text":"Only admins can move jobs into this stage"},{"id":"d","text":"The stage has reached its WIP limit and no more jobs can enter"}],"explanation":"Irreversible stages prevent backward movement. This is used for stages with accounting documents attached (Invoice, Payment) where moving a job backward would create financial inconsistencies."},{"id":"ad7","text":"You need to see who changed a system setting last Tuesday. Where do you look?","options":[{"id":"a","text":"Admin → Audit Log — filter by entity type SystemSetting and the date range","isCorrect":true},{"id":"b","text":"Admin → Settings → Change History"},{"id":"c","text":"Reports → Admin Activity"},{"id":"d","text":"There is no audit trail for settings changes"}],"explanation":"The Audit Log records every change to every entity, including system settings. Filter by entity type SystemSetting and the relevant date to see exactly who changed what, with before and after values."},{"id":"ad8","text":"You're configuring QuickBooks Online integration. What happens after you click 'Connect QuickBooks'?","options":[{"id":"a","text":"You enter your QBO credentials directly in QB Engineer"},{"id":"b","text":"You're redirected to the Intuit OAuth consent screen to authorize the connection","isCorrect":true},{"id":"c","text":"QB Engineer downloads your QBO data automatically without any authorization"},{"id":"d","text":"A support ticket is created to manually connect the systems"}],"explanation":"QuickBooks uses OAuth 2.0. Clicking Connect redirects you to Intuit's consent screen where you sign in and authorize QB Engineer. You're then returned with the connection active."},{"id":"ad9","text":"An employee's badge is not being recognized at the kiosk. Where do you check their scan identifier?","options":[{"id":"a","text":"Admin → Teams & Kiosks → Badge Management"},{"id":"b","text":"Admin → Users → edit the user → Scan Identifiers section","isCorrect":true},{"id":"c","text":"Account → Security → Badge Settings"},{"id":"d","text":"The kiosk terminal itself has a badge registration screen"}],"explanation":"Scan identifiers (RFID, NFC, barcode) are managed per-user in Admin → Users. Edit the user and look at the Scan Identifiers section to add, remove, or verify their badge ID."},{"id":"ad10","text":"You want to require all managers to use MFA (multi-factor authentication). Where do you configure this?","options":[{"id":"a","text":"Admin → Settings → Security → MFA Settings"},{"id":"b","text":"Admin → MFA Policy — select 'Manager' in the Required for Roles multi-select and click Save","isCorrect":true},{"id":"c","text":"Each manager must enable MFA individually from their Account → Security"},{"id":"d","text":"MFA is all-or-nothing — you cannot enforce it by role"}],"explanation":"The MFA Policy tab lets you select which roles require MFA. Select Manager (and any other roles), click Save. Users in those roles will be prompted to set up TOTP on their next login."},{"id":"ad11","text":"A compliance template shows a 'No Form Definition' warning. What does this mean?","options":[{"id":"a","text":"The template was created but no employees have submitted it yet"},{"id":"b","text":"The template doesn't have a form definition — you need to upload a PDF and run field extraction, or manually configure the fields","isCorrect":true},{"id":"c","text":"The template is disabled and needs to be reactivated"},{"id":"d","text":"The PDF upload failed and needs to be retried"}],"explanation":"A 'No Form Definition' warning means the template exists but has no renderable form fields. Click Extract Definition to upload a PDF and use AI-powered extraction, or manually configure the field layout."},{"id":"ad12","text":"You need to add a new expense category called 'Travel - Lodging' to the system. Where do you do this?","options":[{"id":"a","text":"Expenses page → Settings → Categories"},{"id":"b","text":"Admin → Reference Data → expand the Expense Categories group → Add Item","isCorrect":true},{"id":"c","text":"Admin → Settings → System Settings → Expense Categories"},{"id":"d","text":"It's hardcoded — you cannot add custom expense categories"}],"explanation":"All dropdown values including expense categories are managed in Admin → Reference Data. Find the Expense Categories group, click Add Item, enter the label and code, and save."},{"id":"ad13","text":"The track type code field only accepts a specific format. What is it?","options":[{"id":"a","text":"Any text is allowed — there are no format restrictions"},{"id":"b","text":"Uppercase letters, numbers, and underscores only (e.g., PRODUCTION, R_AND_D)","isCorrect":true},{"id":"c","text":"Lowercase letters and hyphens (e.g., production, r-and-d)"},{"id":"d","text":"Numeric codes only (e.g., 001, 002)"}],"explanation":"Track type codes must match the pattern ^[A-Z0-9_]+$ — uppercase letters, numbers, and underscores only. This ensures consistency as codes are used internally as immutable identifiers."},{"id":"ad14","text":"What happens when you lock a pay period through a specific date?","options":[{"id":"a","text":"Employees cannot submit expenses after that date"},{"id":"b","text":"Time entries on or before that date can no longer be modified by employees or managers","isCorrect":true},{"id":"c","text":"The payroll report for that period is automatically generated"},{"id":"d","text":"All jobs due before that date are automatically archived"}],"explanation":"Pay period locking prevents modifications to time entries within the locked period. This ensures payroll data integrity once it has been processed."},{"id":"ad15","text":"You created a new training module but employees can't see it. What is the most likely issue?","options":[{"id":"a","text":"The module hasn't been added to a training path yet"},{"id":"b","text":"The module's Published toggle is set to OFF — employees only see published modules","isCorrect":true},{"id":"c","text":"The module's content type is not supported by the training viewer"},{"id":"d","text":"New modules require a system restart to appear"}],"explanation":"Training modules have a Published toggle. When OFF (Draft), the module is invisible to regular users. Toggle it ON in Admin → Training → Content tab to make it visible."}]}"""
